protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Blog>(entity =>
    {
        // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
        // Keep the old name so existing documents and raw SQL queries
        // (e.g. WHERE c.Discriminator = 'Blog') continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer includes the discriminator in the synthesized
        // JSON "id" value. Existing documents use "Blog|1" format, so opt back in.
        entity.HasDiscriminatorInJsonId();
    });

    // Removed: HasIndex() — EF Core 9 Cosmos provider now throws
    // instead of silently ignoring unsupported indexes.
}

